<script setup lang="ts">import {ref} from 'vue';import {usePlatformStore} from '../stores/platform';const store=usePlatformStore();const email=ref('');const password=ref('');async function submit(){try{await store.login(email.value,password.value)}catch{/* safe message is rendered below */}}</script>
<template><main class="login"><section><div class="mark">O</div><p class="eyebrow">Restricted operations access</p><h1>Platform staff sign in</h1><p class="muted">Use your individual staff account. Sensitive actions require a fresh password confirmation and are audited.</p><el-alert v-if="store.authError" :title="store.authError" type="error" :closable="false" show-icon/><el-form label-position="top"><el-form-item label="Email"><el-input v-model="email" type="email" autocomplete="username"/></el-form-item><el-form-item label="Password"><el-input v-model="password" type="password" show-password autocomplete="current-password" @keyup.enter="submit"/></el-form-item><el-button type="primary" class="submit" :loading="store.refreshing" @click="submit">Sign in</el-button></el-form><small>Sessions expire after 12 hours and are stored only in this browser tab.</small></section></main></template>
